"""
Quick-and-dirty auth module with login/register/reset functionality.
WARNING: This is intentionally simplified and NOT production-ready.
"""

import hashlib
import os
import secrets
import time
from dataclasses import dataclass, field
from typing import Optional


@dataclass
class User:
    username: str
    password_hash: bytes
    password_salt: bytes
    email: str
    created_at: float = field(default_factory=time.time)
    reset_token: Optional[str] = None
    reset_token_expiry: Optional[float] = None


class AuthModule:
    HASH_ITERATIONS = 100_000

    def __init__(self):
        self._users: dict[str, User] = {}
        self._sessions: dict[str, str] = {}  # token -> username

    def _hash_password(self, password: str, salt: Optional[bytes] = None) -> tuple[bytes, bytes]:
        """PBKDF2-HMAC-SHA256 with random salt. Returns (hash, salt)."""
        if salt is None:
            salt = os.urandom(16)
        password_hash = hashlib.pbkdf2_hmac(
            'sha256',
            password.encode(),
            salt,
            self.HASH_ITERATIONS
        )
        return password_hash, salt

    def _verify_password(self, password: str, stored_hash: bytes, salt: bytes) -> bool:
        """Verify password against stored hash and salt."""
        computed_hash, _ = self._hash_password(password, salt)
        return secrets.compare_digest(computed_hash, stored_hash)

    def _generate_token(self) -> str:
        return secrets.token_urlsafe(32)

    def register(self, username: str, password: str, email: str) -> dict:
        """Register a new user."""
        if not username or not password or not email:
            return {"success": False, "error": "All fields required"}

        if username in self._users:
            return {"success": False, "error": "Username already exists"}

        if len(password) < 6:
            return {"success": False, "error": "Password must be at least 6 characters"}

        password_hash, salt = self._hash_password(password)
        user = User(
            username=username,
            password_hash=password_hash,
            password_salt=salt,
            email=email,
        )
        self._users[username] = user
        return {"success": True, "message": "User registered successfully"}

    def login(self, username: str, password: str) -> dict:
        """Login and return a session token."""
        if username not in self._users:
            return {"success": False, "error": "Invalid credentials"}

        user = self._users[username]
        if not self._verify_password(password, user.password_hash, user.password_salt):
            return {"success": False, "error": "Invalid credentials"}

        token = self._generate_token()
        self._sessions[token] = username
        return {"success": True, "token": token}

    def logout(self, token: str) -> dict:
        """Invalidate a session token."""
        if token in self._sessions:
            del self._sessions[token]
            return {"success": True, "message": "Logged out"}
        return {"success": False, "error": "Invalid token"}

    def verify_session(self, token: str) -> Optional[str]:
        """Return username if token is valid, None otherwise."""
        return self._sessions.get(token)

    def request_password_reset(self, username: str) -> dict:
        """Generate a password reset token (would email in production)."""
        if username not in self._users:
            # Return success anyway to prevent username enumeration
            return {"success": True, "message": "If user exists, reset email sent"}

        user = self._users[username]
        user.reset_token = self._generate_token()
        user.reset_token_expiry = time.time() + 3600  # 1 hour expiry

        # In production, this would send an email
        return {
            "success": True,
            "message": "If user exists, reset email sent",
            "_debug_token": user.reset_token,  # Only for testing!
        }

    def reset_password(self, username: str, token: str, new_password: str) -> dict:
        """Reset password using a valid reset token."""
        if username not in self._users:
            return {"success": False, "error": "Invalid reset request"}

        user = self._users[username]

        if not user.reset_token or not secrets.compare_digest(user.reset_token, token):
            return {"success": False, "error": "Invalid reset token"}

        if user.reset_token_expiry and time.time() > user.reset_token_expiry:
            return {"success": False, "error": "Reset token expired"}

        if len(new_password) < 6:
            return {"success": False, "error": "Password must be at least 6 characters"}

        password_hash, salt = self._hash_password(new_password)
        user.password_hash = password_hash
        user.password_salt = salt
        user.reset_token = None
        user.reset_token_expiry = None

        # Invalidate all existing sessions for this user
        self._sessions = {k: v for k, v in self._sessions.items() if v != username}

        return {"success": True, "message": "Password reset successfully"}


# Simple usage example
if __name__ == "__main__":
    auth = AuthModule()

    # Register
    print(auth.register("alice", "password123", "alice@example.com"))

    # Login
    result = auth.login("alice", "password123")
    print(result)

